 *    5. footer에 값 처리
 * 참고사항 :
 *    1. 엑셀다운로드 시 Number타입 excelFormat, excelCellType 옵션 추가 작업
 * 수정이력 :
 *    - 2026-01-03      배기원    최초작성
 */
scwin.params;
/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function () {
     const codeOptions = [
           { grpCd: "ZZ001", compID: "gr_txn:sysCd" }  //시스템코드
     ];
    $c.data.setCommonCode(codeOptions);

    scwin.params = $c.data.getParameter();

    scwin.f_HeaderCreate();
    scwin.f_Retrieve();
};

/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function () {
    gr_txn.setNoResultMessageVisible(false);
    gr_txn.setColumnColor("internalTxnBilgNo", "#007FFF");
    ds_txn.reform();
    ds_txn.removeAll();
    totalRows.setValue("0");
};

/**
 * 데이터셋 세팅
